import { resolveMetro } from './metros.js';

/** Convenience: activities active for `code` in given 0-11 month, or [] when unknown.
 *  Falls through metro->primary-airport (e.g. NYC->JFK) so Travelpayouts metro codes
 *  also surface seasonal chips. (HC 2026-06-04 #AIRPORT-COVERAGE) */
export function activitiesFor(code: string, month: number): SeasonalActivity[] {
  const upper = code.toUpperCase();
  let entries = SEASONAL_ACTIVITIES[upper];
  if (!entries) {
    const metro = resolveMetro(upper);
    if (metro) entries = SEASONAL_ACTIVITIES[metro];
  }
  if (!entries) return [];
  const hit = entries.find(([m]) => m === month);
  return hit ? hit[1] : [];
}
